    private static function settings() { return wp_parse_args((array)get_option('tager_v24_settings', []), self::defaults()); }

    private static function calculate_shipping($s, $gov, $subtotal, $vendor_count, $mode) {
        if (empty($s['shipping_enabled'])) return ['fee'=>0,'days'=>0,'label'=>'disabled'];
        $zone = $s['shipping'][$gov] ?? ['fee'=>0,'days'=>3,'enabled'=>1,'free_threshold'=>0];
        if (isset($zone['enabled']) && empty($zone['enabled'])) return ['fee'=>0,'days'=>(int)($zone['days']??3),'label'=>'unavailable'];
        if (!empty($s['free_shipping_enabled']) && (float)$s['free_shipping_threshold'] > 0 && $subtotal >= (float)$s['free_shipping_threshold']) return ['fee'=>0,'days'=>(int)($zone['days']??3),'label'=>'free'];
        if (!empty($zone['free_threshold']) && $subtotal >= (float)$zone['free_threshold']) return ['fee'=>0,'days'=>(int)($zone['days']??3),'label'=>'free'];
        $fee = ($s['shipping_mode'] ?? 'governorate') === 'flat' ? (float)($s['flat_shipping_fee'] ?? 0) : (float)($zone['fee'] ?? 0);
        if (!empty($s['charge_per_vendor'])) $fee *= max(1, (int)$vendor_count);
        $fee += max(0, (float)($s['per_vendor_handling_fee'] ?? 0)) * max(1, (int)$vendor_count);
        if ($mode === 'mixed') {
            $extra = max(0, (float)($s['mixed_cart_shipping_surcharge'] ?? 0));
            $fee += ($s['mixed_cart_shipping_surcharge_type'] ?? 'fixed') === 'percent' ? (($fee * $extra) / 100) : $extra;
        }
        return ['fee'=>round(max(0,$fee),2),'days'=>(int)($zone['days']??3),'label'=>$fee>0?'paid':'free'];
    }

    private static function vendor_min($vendor_id) { $v=(float)get_user_meta($vendor_id,'tager_vendor_min_order',true); return $v>0?$v:500; }
    private static function vendor_name($vendor_id) { return get_user_meta($vendor_id,'store_name',true) ?: get_the_author_meta('display_name',$vendor_id); }
    private static function product_price($id,$qty){
        $r=(float)get_post_meta($id,'retail_price',true);$w=(float)get_post_meta($id,'wholesale_price',true);$b=(float)get_post_meta($id,'bulk_price',true);$wm=(int)get_post_meta($id,'wholesale_min',true);$bm=(int)get_post_meta($id,'bulk_min',true);
        if($bm>0&&$qty>=$bm)return $b;if($wm>0&&$qty>=$wm)return $w;return $r;
    }

    public static function replace_checkout(){
        remove_shortcode('tager_cart'); add_shortcode('tager_cart',[__CLASS__,'cart_page']);
        remove_shortcode('tager_v23_cart'); add_shortcode('tager_v23_cart',[__CLASS__,'cart_page']);
        if(class_exists('Tager_V23_Vendor_Cart_Egypt')){
            remove_action('admin_post_tager_checkout',['Tager_V23_Vendor_Cart_Egypt','checkout']);
            remove_action('admin_post_nopriv_tager_checkout',['Tager_V23_Vendor_Cart_Egypt','checkout']);
        }
        if(class_exists('Tager_Marketplace_Complete')){
            remove_action('admin_post_tager_checkout',['Tager_Marketplace_Complete','handle_checkout']);
            remove_action('admin_post_nopriv_tager_checkout',['Tager_Marketplace_Complete','handle_checkout']);
        }
    }

