    private static function catalog(){
        $posts=get_posts(['post_type'=>'tager_product','post_status'=>'publish','numberposts'=>-1]);$d=[];
        foreach($posts as $p){$v=(int)$p->post_author;$d[$p->ID]=['id'=>$p->ID,'name'=>$p->post_title,'vendor_id'=>$v,'vendor_name'=>self::vendor_name($v),'vendor_min'=>self::vendor_min($v),'stock'=>(int)get_post_meta($p->ID,'stock',true),'max'=>(int)(get_post_meta($p->ID,'max_qty',true)?:9999),'retail'=>(float)get_post_meta($p->ID,'retail_price',true),'wholesale'=>(float)get_post_meta($p->ID,'wholesale_price',true),'bulk'=>(float)get_post_meta($p->ID,'bulk_price',true),'wholesale_min'=>(int)get_post_meta($p->ID,'wholesale_min',true),'bulk_min'=>(int)get_post_meta($p->ID,'bulk_min',true),'store_url'=>add_query_arg('vendor',$v,self::url('vendor-store'))];}
        return $d;
    }

