              <label class="v24-terms"><input type="checkbox" required name="accept_terms" value="1"> <?php echo esc_html(self::t('أوافق على الشروط وسياسة الشحن والاسترجاع، وأقر بصحة بيانات الطلب.','I agree to the terms, shipping and return policy, and confirm that the order data is correct.')); ?></label>
              <button class="btn primary" id="v24-place-order" style="width:100%;margin-top:14px"><?php echo esc_html(self::t('تأكيد الطلب','Place order')); ?></button><div class="v24-secure">🔒 <?php echo esc_html(self::t('لا يتم حفظ بيانات البطاقة داخل الموقع. الدفع الإلكتروني الحقيقي يحتاج بوابة دفع معتمدة.','Card data is never stored on the site. Real online payment requires an approved gateway.')); ?></div>
            </form><?php endif; ?>
          </main>
          <aside class="v24-summary v24-panel"><h2><?php echo esc_html(self::t('اختَر نوع السلة','Choose your cart type')); ?></h2><p class="v27-cart-help"><?php echo esc_html(self::t('الاختيار للعميل قبل تأكيد الطلب، ويمكن تغييره في أي وقت قبل الدفع.','The customer chooses before placing the order and can change it any time before payment.')); ?></p><div class="v23-mode v27-cart-types"><label class="v27-cart-card"><input type="radio" name="v24_mode" value="vendor"><span class="v27-cart-icon">🏪</span><span><b><?php echo esc_html(self::t('سلة الموردين المنفصلة','Separate vendor carts')); ?></b><small><?php echo esc_html(self::t('يتم حساب كل مورد بمفرده ويجب تحقيق الحد الأدنى الخاص به. لا توجد رسوم السلة المختلطة.','Each vendor is calculated separately and its minimum order must be reached. No mixed-cart fee.')); ?></small></span><em><?php echo esc_html(self::t('بدون رسوم إضافية','No extra mixed fee')); ?></em></label><label class="v27-cart-card featured"><input type="radio" name="v24_mode" value="mixed"><span class="v27-cart-icon">🛒</span><span><b><?php echo esc_html(self::t('السلة الخاصة المختلطة','Special mixed cart')); ?></b><small><?php echo esc_html(self::t('اطلب أي أصناف من جميع الموردين في طلب واحد دون الالتزام بحد كل مورد.','Order any products from all vendors in one order without meeting each vendor minimum.')); ?></small></span><em><?php echo esc_html(sprintf(self::t('رسوم خدمة %s%%','%s%% service fee'),number_format((float)$s['mixed_cart_fee_percent'],1))); ?></em></label></div><div id="v27-cart-choice-warning" class="notice" style="margin:12px 0"><?php echo esc_html(self::t('اختر نوع السلة أولًا لعرض الإجمالي والسماح بتأكيد الطلب.','Choose a cart type first to calculate the total and enable checkout.')); ?></div><h2 class="v27-summary-title"><?php echo esc_html(self::t('ملخص الطلب','Order summary')); ?></h2><div class="v24-total"><span><?php echo esc_html(self::t('المنتجات','Products')); ?></span><b id="v24-subtotal">0.00 EGP</b></div><div class="v24-total" id="v24-mixed-row" style="display:none"><span><?php echo esc_html(self::t('رسوم السلة المختلطة','Mixed-cart fee')); ?></span><b id="v24-mixed-fee">0.00 EGP</b></div><div class="v24-total"><span><?php echo esc_html(self::t('الشحن','Shipping')); ?></span><b id="v24-shipping">—</b></div><div class="v24-total"><span><?php echo esc_html(self::t('رسوم الخدمة','Service fee')); ?></span><b id="v26-service-fee">0.00 EGP</b></div><div class="v24-total" id="v26-small-row" style="display:none"><span><?php echo esc_html(self::t('رسوم الطلب الصغير','Small-order fee')); ?></span><b id="v26-small-fee">0.00 EGP</b></div><div class="v24-total"><span><?php echo esc_html(self::t('رسوم الدفع','Payment fee')); ?></span><b id="v24-payment-fee">0.00 EGP</b></div><div class="v24-total grand"><span><?php echo esc_html(self::t('الإجمالي النهائي','Final total')); ?></span><b id="v24-grand">0.00 EGP</b></div><div id="v24-validation"></div></aside>
        </div>
        <script>(function(){
          const CATALOG=<?php echo wp_json_encode(self::catalog(),JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES); ?>;
          const SETTINGS=<?php echo wp_json_encode(['bank'=>$s['bank_details'],'instapay'=>$s['instapay_address'],'wallet'=>$s['wallet_number'],'card_demo'=>(bool)$s['card_demo'],'shipping_enabled'=>(bool)$s['shipping_enabled'],'shipping_mode'=>$s['shipping_mode'],'flat_shipping_fee'=>(float)$s['flat_shipping_fee'],'free_shipping_enabled'=>(bool)$s['free_shipping_enabled'],'free_shipping_threshold'=>(float)$s['free_shipping_threshold'],'charge_per_vendor'=>(bool)$s['charge_per_vendor'],'per_vendor_handling_fee'=>(float)$s['per_vendor_handling_fee'],'mixed_cart_shipping_surcharge_type'=>$s['mixed_cart_shipping_surcharge_type'],'mixed_cart_shipping_surcharge'=>(float)$s['mixed_cart_shipping_surcharge'],'mixed_cart_fee_percent'=>(float)$s['mixed_cart_fee_percent'],'platform_fee_type'=>$s['platform_fee_type'],'platform_fee'=>(float)$s['platform_fee'],'small_order_threshold'=>(float)$s['small_order_threshold'],'small_order_fee'=>(float)$s['small_order_fee'],'cod_max_total'=>(float)$s['cod_max_total'],'pickup_enabled'=>(bool)$s['pickup_enabled'],'express_enabled'=>(bool)$s['express_enabled'],'express_fee'=>(float)$s['express_fee'],'express_days'=>(int)$s['express_days']],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES); ?>;
          const TXT={empty:<?php echo wp_json_encode(self::t('السلة فارغة','Your cart is empty')); ?>,remaining:<?php echo wp_json_encode(self::t('متبقي للحد الأدنى','Remaining to minimum')); ?>,reached:<?php echo wp_json_encode(self::t('تم تحقيق الحد الأدنى','Minimum reached')); ?>,invalid:<?php echo wp_json_encode(self::t('استكمل الحد الأدنى لكل مورد أو اختر السلة المختلطة.','Reach each vendor minimum or select the mixed cart.')); ?>,delivery:<?php echo wp_json_encode(self::t('التوصيل المتوقع','Estimated delivery')); ?>,days:<?php echo wp_json_encode(self::t('أيام عمل','business days')); ?>,free:<?php echo wp_json_encode(self::t('مجاني','Free')); ?>,unavailable:<?php echo wp_json_encode(self::t('الشحن غير متاح لهذه المحافظة','Shipping is unavailable for this governorate')); ?>};
          function cart(){try{return JSON.parse(localStorage.getItem('tager_cart')||'[]')}catch(e){return []}} function money(v){return Number(v||0).toFixed(2)+' EGP'} function price(p,q){return p.bulk_min&&q>=p.bulk_min?p.bulk:(p.wholesale_min&&q>=p.wholesale_min?p.wholesale:p.retail)}
          function groups(){let g={};cart().forEach((x,i)=>{let p=CATALOG[x.id];if(!p)return;let q=Math.max(1,Math.min(parseInt(x.qty||1),p.max||9999,p.stock||9999));if(!g[p.vendor_id])g[p.vendor_id]={vendor:p.vendor_name,min:Number(p.vendor_min||0),url:p.store_url,items:[],subtotal:0};let unit=price(p,q),line=unit*q;g[p.vendor_id].items.push({index:i,p,q,unit,line});g[p.vendor_id].subtotal+=line});return g}
          window.v24Remove=function(i){let c=cart();c.splice(i,1);localStorage.setItem('tager_cart',JSON.stringify(c));render()};window.v24Qty=function(i,v){let c=cart(),p=CATALOG[c[i].id];c[i].qty=Math.max(1,Math.min(parseInt(v||1),p.max||9999,p.stock||9999));localStorage.setItem('tager_cart',JSON.stringify(c));render()};
          function method(){return document.querySelector('input[name=payment_method]:checked')} function selectedMode(){return document.querySelector('input[name=v24_mode]:checked')?.value||''} function mode(){return selectedMode()}
          function paymentInfo(){let m=method(),key=m?.value||'';let info='';if(key==='bank')info='<b><?php echo esc_js(self::t('بيانات التحويل البنكي','Bank transfer details')); ?>:</b><br>'+SETTINGS.bank;if(key==='instapay')info='<b>InstaPay:</b> '+SETTINGS.instapay;if(key==='wallet')info='<b><?php echo esc_js(self::t('رقم المحفظة','Wallet number')); ?>:</b> '+SETTINGS.wallet;if(key==='fawry')info='<?php echo esc_js(self::t('سيظهر مرجع فوري بعد تسجيل الطلب. التفعيل التجاري يحتاج الربط مع فوري.','A Fawry reference will appear after order creation. Commercial activation requires Fawry integration.')); ?>';if(key==='card')info=SETTINGS.card_demo?'<?php echo esc_js(self::t('وضع تجريبي: لن يتم خصم مبلغ حقيقي. سيُحفظ الطلب بانتظار الدفع.','Demo mode: no real charge will occur. The order will be saved as awaiting payment.')); ?>':'';document.getElementById('v24-method-info').innerHTML=info||'<?php echo esc_js(self::t('اختر الطريقة الأنسب لك.','Choose the most convenient method.')); ?>';let need=['bank','instapay','wallet'].includes(key);document.getElementById('v24-reference').style.display=need?'block':'none';document.getElementById('v24-payment-reference').required=need}
          function totals(){let g=groups(),subtotal=Object.values(g).reduce((a,v)=>a+v.subtotal,0),selected=mode(),mixed=selected==='mixed',mixedFee=mixed?subtotal*(Number(SETTINGS.mixed_cart_fee_percent||1.5)/100):0,gov=document.getElementById('v24-governorate'),op=gov?.selectedOptions[0],ship=0,shippingUnavailable=false;let delivery=document.getElementById('v26-delivery-method')?.value||'standard';if(delivery==='pickup'){ship=0}else if(SETTINGS.shipping_enabled&&op&&op.value){if(op.dataset.enabled==='0'){shippingUnavailable=true}else if((SETTINGS.free_shipping_enabled&&SETTINGS.free_shipping_threshold>0&&subtotal>=SETTINGS.free_shipping_threshold)||(Number(op.dataset.freeThreshold||0)>0&&subtotal>=Number(op.dataset.freeThreshold||0))){ship=0}else{ship=SETTINGS.shipping_mode==='flat'?Number(SETTINGS.flat_shipping_fee||0):Number(op.dataset.fee||0);if(SETTINGS.charge_per_vendor)ship*=Math.max(1,Object.keys(g).length);ship+=Number(SETTINGS.per_vendor_handling_fee||0)*Math.max(1,Object.keys(g).length);if(mixed){let x=Number(SETTINGS.mixed_cart_shipping_surcharge||0);ship+=SETTINGS.mixed_cart_shipping_surcharge_type==='percent'?ship*x/100:x}}if(delivery==='express')ship+=Number(SETTINGS.express_fee||0)}let serviceFee=SETTINGS.platform_fee_type==='percent'?subtotal*Number(SETTINGS.platform_fee||0)/100:Number(SETTINGS.platform_fee||0),smallFee=(Number(SETTINGS.small_order_threshold||0)>0&&subtotal<Number(SETTINGS.small_order_threshold||0))?Number(SETTINGS.small_order_fee||0):0,m=method(),pf=0;if(m){let val=Number(m.dataset.fee||0);pf=m.dataset.feeType==='percent'?(subtotal+mixedFee+ship)*val/100:val}let totalBeforePayment=subtotal+mixedFee+ship+serviceFee+smallFee;if(m&&m.value==='cod'&&Number(SETTINGS.cod_max_total||0)>0&&totalBeforePayment>Number(SETTINGS.cod_max_total||0)){pf=0}return {g,subtotal,selected,mixed,mixedFee,ship,shippingUnavailable,serviceFee,smallFee,pf,total:totalBeforePayment+pf,delivery}}
          function render(){let t=totals(),keys=Object.keys(t.g),valid=true,root=document.getElementById('v24-groups');if(!keys.length)root.innerHTML='<div class="notice">'+TXT.empty+'</div>';else root.innerHTML=keys.map(k=>{let v=t.g[k],ok=v.subtotal>=v.min,pct=v.min?Math.min(100,v.subtotal/v.min*100):100;if(!ok)valid=false;return '<section class="v24-vendor"><header class="v24-vendor-head"><div><b><a href="'+v.url+'">'+v.vendor+'</a></b><div>'+(ok?'<span class="v24-chip">'+TXT.reached+'</span>':'<span class="v24-chip warn">'+TXT.remaining+': '+money(v.min-v.subtotal)+'</span>')+'<div class="v24-progress"><i style="width:'+pct+'%"></i></div></div></div><b>'+money(v.subtotal)+'</b></header>'+v.items.map(it=>'<div class="v24-row"><div><b>'+it.p.name+'</b><small><br>'+money(it.unit)+' / unit</small></div><input type="number" min="1" max="'+Math.min(it.p.max,it.p.stock)+'" value="'+it.q+'" onchange="v24Qty('+it.index+',this.value)"><b class="line">'+money(it.line)+'</b><button type="button" onclick="v24Remove('+it.index+')">×</button></div>').join('')+'</section>'}).join('');document.getElementById('v24-subtotal').textContent=money(t.subtotal);document.getElementById('v24-mixed-row').style.display=t.mixed?'flex':'none';document.getElementById('v24-mixed-fee').textContent=money(t.mixedFee);document.getElementById('v24-shipping').textContent=document.getElementById('v24-governorate')?.value?(t.shippingUnavailable?TXT.unavailable:(t.ship===0?TXT.free:money(t.ship))):'—';document.getElementById('v26-service-fee').textContent=money(t.serviceFee);document.getElementById('v26-small-row').style.display=t.smallFee>0?'flex':'none';document.getElementById('v26-small-fee').textContent=money(t.smallFee);document.getElementById('v24-payment-fee').textContent=money(t.pf);document.getElementById('v24-grand').textContent=t.selected?money(t.total):'—';document.getElementById('v24-mode-hidden').value=t.selected;document.getElementById('v24-calculated-total').value=t.selected?t.total.toFixed(2):'';let choiceWarn=document.getElementById('v27-cart-choice-warning');if(choiceWarn)choiceWarn.style.display=t.selected?'none':'block';document.querySelectorAll('.v27-cart-card').forEach(x=>x.classList.toggle('selected',!!x.querySelector('input:checked')));document.getElementById('v24-validation').innerHTML=t.selected&&(!t.mixed&&!valid)?'<div class="notice" style="margin-top:12px">'+TXT.invalid+'</div>':'';let btn=document.getElementById('v24-place-order');if(btn)btn.disabled=!t.selected||!keys.length||(!t.mixed&&!valid)||t.shippingUnavailable;paymentInfo()}
          document.querySelectorAll('input[name=v24_mode]').forEach(x=>x.addEventListener('change',function(){localStorage.setItem('tager_cart_mode',this.value);render()}));document.querySelectorAll('input[name=payment_method]').forEach(x=>x.addEventListener('change',render));let savedMode=localStorage.getItem('tager_cart_mode');if(['vendor','mixed'].includes(savedMode)){let saved=document.querySelector('input[name=v24_mode][value="'+savedMode+'"]');if(saved)saved.checked=true;}document.getElementById('v26-delivery-method')?.addEventListener('change',function(){let pick=document.getElementById('v26-pickup-info');if(pick)pick.style.display=this.value==='pickup'?'block':'none';render()});document.getElementById('v24-governorate')?.addEventListener('change',function(){let o=this.selectedOptions[0],card=document.getElementById('v24-delivery-estimate');if(this.value){let t=totals();card.style.display='flex';card.innerHTML='<span>'+TXT.delivery+'</span><b>'+(t.shippingUnavailable?TXT.unavailable:(o.dataset.days+' '+TXT.days+' · '+(t.ship===0?TXT.free:money(t.ship))))+'</b>'}else card.style.display='none';render()});document.getElementById('v24-invoice-type')?.addEventListener('change',function(){document.getElementById('v24-business-fields').style.display=this.value==='business'?'grid':'none'});document.getElementById('v24-checkout')?.addEventListener('submit',function(e){let t=totals();if(!t.selected){e.preventDefault();alert(<?php echo wp_json_encode(self::t('اختر نوع السلة أولًا.','Choose a cart type first.')); ?>);return}if(!cart().length||t.shippingUnavailable||(!t.mixed&&Object.values(t.g).some(v=>v.subtotal<v.min))){e.preventDefault();alert(TXT.invalid);return}document.getElementById('v24-cart-json').value=JSON.stringify(cart());document.getElementById('v24-mode-hidden').value=t.selected;let b=document.getElementById('v24-place-order');b.disabled=true;b.textContent='<?php echo esc_js(self::t('جاري إنشاء الطلب...','Creating order...')); ?>'});render();
        })();</script>
        <?php return ob_get_clean();
    }

    private static function upload_proof($order_id){
        if(empty($_FILES['payment_proof']['name']))return 0;if(!function_exists('wp_handle_upload'))require_once ABSPATH.'wp-admin/includes/file.php';
        $f=$_FILES['payment_proof'];if((int)$f['size']>4*1024*1024)wp_die('Payment proof file is too large.');$allowed=['image/jpeg','image/png','image/webp','application/pdf'];$type=wp_check_filetype_and_ext($f['tmp_name'],$f['name']);if(empty($type['type'])||!in_array($type['type'],$allowed,true))wp_die('Invalid payment proof file type.');
        $up=wp_handle_upload($f,['test_form'=>false]);if(!empty($up['error']))wp_die(esc_html($up['error']));$att=wp_insert_attachment(['post_mime_type'=>$up['type'],'post_title'=>'Payment proof order '.$order_id,'post_status'=>'inherit'],$up['file'],$order_id);if($att&&!is_wp_error($att)){require_once ABSPATH.'wp-admin/includes/image.php';wp_update_attachment_metadata($att,wp_generate_attachment_metadata($att,$up['file']));return (int)$att;}return 0;
    }

    public static function checkout(){
        check_admin_referer('tager_checkout');if(!is_user_logged_in())wp_die('Login required');if(empty($_POST['accept_terms']))wp_die('Terms acceptance is required.');
        $cart=json_decode(stripslashes($_POST['cart_json']??'[]'),true);if(!$cart||!is_array($cart))wp_die('Empty cart');$s=self::settings();$mode=sanitize_key($_POST['cart_mode']??'');if(!in_array($mode,['vendor','mixed'],true))wp_die('Choose a cart type before checkout.');$method=sanitize_key($_POST['payment_method']??'');if(empty($s['methods'][$method]['enabled']))wp_die('Invalid payment method.');$gov=sanitize_text_field($_POST['governorate']??'');if(!isset(self::governorates()[$gov]))wp_die('Invalid governorate.');
        $groups=[];$lines=[];$subtotal=0;
        foreach($cart as $item){$id=(int)($item['id']??0);$p=get_post($id);if(!$p||$p->post_type!=='tager_product'||$p->post_status!=='publish')wp_die('Invalid product');$qty=max(1,(int)($item['qty']??1));$stock=(int)get_post_meta($id,'stock',true);$max=(int)(get_post_meta($id,'max_qty',true)?:9999);if($qty>$stock||$qty>$max)wp_die('Quantity exceeds stock or limits');$vendor=(int)$p->post_author;$unit=self::product_price($id,$qty);$line=$unit*$qty;$subtotal+=$line;if(!isset($groups[$vendor]))$groups[$vendor]=['vendor_id'=>$vendor,'vendor_name'=>self::vendor_name($vendor),'minimum'=>self::vendor_min($vendor),'subtotal'=>0,'items'=>[]];$row=['id'=>$id,'name'=>$p->post_title,'qty'=>$qty,'unit_price'=>$unit,'line_total'=>$line,'vendor_id'=>$vendor];$groups[$vendor]['items'][]=$row;$groups[$vendor]['subtotal']+=$line;$lines[]=$row;}
        if($mode==='vendor')foreach($groups as $g)if($g['subtotal']+0.0001<$g['minimum'])wp_die('Vendor minimum order was not reached.');
        $mixed_percent=max(0,(float)($s['mixed_cart_fee_percent']??self::MIXED_FEE_PERCENT));$mixed_fee=0;$mixed_fee_breakdown=[];if($mode==='mixed'){foreach($groups as $vendor_id=>$group){$vendor_rate=get_user_meta((int)$vendor_id,'tager_vendor_mixed_fee_percent',true);$vendor_rate=$vendor_rate===''?$mixed_percent:max(0,min(20,(float)$vendor_rate));$vendor_fee=round((float)$group['subtotal']*$vendor_rate/100,2);$mixed_fee+=$vendor_fee;$mixed_fee_breakdown[]=['vendor_id'=>(int)$vendor_id,'vendor_name'=>$group['vendor_name'],'subtotal'=>(float)$group['subtotal'],'rate'=>$vendor_rate,'fee'=>$vendor_fee];}$mixed_fee=round($mixed_fee,2);}$shipping_calc=self::calculate_shipping($s,$gov,$subtotal,count($groups),$mode);if($shipping_calc['label']==='unavailable')wp_die('Shipping is unavailable for the selected governorate.');$delivery_method=sanitize_key($_POST['delivery_method']??'standard');if($delivery_method==='pickup'&&!empty($s['pickup_enabled'])){$shipping_calc=['fee'=>0,'days'=>0,'label'=>'pickup'];}elseif($delivery_method==='express'&&!empty($s['express_enabled'])){$shipping_calc['fee']+=(float)$s['express_fee'];$shipping_calc['days']=(int)$s['express_days'];}$ship=(float)$shipping_calc['fee'];$days=(int)$shipping_calc['days'];$service_fee=($s['platform_fee_type']??'fixed')==='percent'?round($subtotal*(float)($s['platform_fee']??0)/100,2):(float)($s['platform_fee']??0);$small_fee=((float)($s['small_order_threshold']??0)>0&&$subtotal<(float)$s['small_order_threshold'])?(float)($s['small_order_fee']??0):0;$m=$s['methods'][$method];$base_before_payment=$subtotal+$mixed_fee+$ship+$service_fee+$small_fee;if($method==='cod'&&(float)($s['cod_max_total']??0)>0&&$base_before_payment>(float)$s['cod_max_total'])wp_die('Cash on delivery is unavailable for this order total.');$payment_fee=$m['fee_type']==='percent'?round(($subtotal+$mixed_fee+$ship)*(float)$m['fee']/100,2):(float)$m['fee'];$total=$subtotal+$mixed_fee+$ship+$service_fee+$small_fee+$payment_fee;
        if(in_array($method,['bank','instapay','wallet'],true)&&empty(trim($_POST['payment_reference']??'')))wp_die('Payment reference is required for this method.');if(($_POST['invoice_type']??'individual')==='business'&&(empty($_POST['company_name'])||empty($_POST['tax_number'])))wp_die('Company name and tax number are required.');
        foreach($lines as $r){$stock=(int)get_post_meta($r['id'],'stock',true);update_post_meta($r['id'],'stock',max(0,$stock-$r['qty']));}
        $uid=get_current_user_id();$order=wp_insert_post(['post_type'=>'tager_order','post_status'=>'publish','post_author'=>$uid,'post_title'=>'Order '.current_time('Ymd-His')]);if(!$order||is_wp_error($order))wp_die('Unable to create order.');
        $data=['customer_name'=>sanitize_text_field($_POST['customer_name']??''),'phone'=>sanitize_text_field($_POST['phone']??''),'email'=>sanitize_email($_POST['email']??''),'governorate'=>$gov,'address'=>sanitize_textarea_field($_POST['address']??''),'notes'=>sanitize_textarea_field($_POST['notes']??''),'invoice_type'=>sanitize_key($_POST['invoice_type']??'individual'),'company_name'=>sanitize_text_field($_POST['company_name']??''),'tax_number'=>sanitize_text_field($_POST['tax_number']??''),'payment_method'=>$method,'payment_method_label'=>self::t($m['name_ar'],$m['name_en']),'payment_reference'=>sanitize_text_field($_POST['payment_reference']??''),'customer_user'=>$uid,'items'=>$lines,'vendor_groups'=>array_values($groups),'cart_mode'=>$mode,'subtotal'=>$subtotal,'mixed_cart_fee'=>$mixed_fee,'mixed_cart_fee_percent'=>$mixed_percent,'mixed_cart_fee_breakdown'=>$mixed_fee_breakdown,'shipping_fee'=>$ship,'delivery_days'=>$days,'delivery_method'=>$delivery_method,'preferred_delivery_date'=>sanitize_text_field($_POST['preferred_delivery_date']??''),'service_fee'=>$service_fee,'small_order_fee'=>$small_fee,'payment_fee'=>$payment_fee,'total'=>$total,'order_status'=>in_array($method,['card','fawry'],true)?'Awaiting payment':'New','payment_status'=>in_array($method,['cod'],true)?'Pay on delivery':(in_array($method,['card','fawry'],true)?'Pending gateway':'Pending verification'),'tracking_code'=>'TGR-'.$order.'-'.wp_rand(1000,9999)];foreach($data as $k=>$v)update_post_meta($order,$k,$v);
        $proof=self::upload_proof($order);if($proof)update_post_meta($order,'payment_proof_attachment',$proof);
        foreach($groups as $vendor=>$g){$sub=wp_insert_post(['post_type'=>'tager_suborder','post_status'=>'publish','post_author'=>$vendor,'post_title'=>'Vendor order '.$order.'-'.$vendor]);if($sub){$base_settings=wp_parse_args((array)get_option('tager_settings',[]),['commission_percent'=>10]);$stored_rate=get_user_meta((int)$vendor,'tager_vendor_commission_percent',true);$commission_rate=$stored_rate===''?max(0,min(100,(float)$base_settings['commission_percent'])):max(0,min(100,(float)$stored_rate));$gross=(float)$g['subtotal'];$commission=round($gross*$commission_rate/100,2);$vendor_net=round($gross-$commission,2);update_post_meta($sub,'parent_order',$order);update_post_meta($sub,'items',$g['items']);update_post_meta($sub,'gross_total',$gross);update_post_meta($sub,'commission_percent',$commission_rate);update_post_meta($sub,'platform_commission',$commission);update_post_meta($sub,'vendor_net',$vendor_net);update_post_meta($sub,'suborder_status','New');update_post_meta($sub,'shipping_governorate',$gov);}}
        wp_safe_redirect(add_query_arg(['msg'=>'order_done','order'=>$order],self::url('my-account')));exit;
    }

