    public static function save_settings(){if(!current_user_can('manage_options'))wp_die('No permission');check_admin_referer('tager_v24_save_settings');$old=self::settings();$methods=[];foreach($old['methods'] as $key=>$m){$in=$_POST['methods'][$key]??[];$methods[$key]=['enabled'=>!empty($in['enabled'])?1:0,'name_ar'=>sanitize_text_field($in['name_ar']??$m['name_ar']),'name_en'=>sanitize_text_field($in['name_en']??$m['name_en']),'fee_type'=>in_array(($in['fee_type']??'fixed'),['fixed','percent'],true)?$in['fee_type']:'fixed','fee'=>max(0,(float)($in['fee']??0)),'instructions_ar'=>sanitize_textarea_field($in['instructions_ar']??''),'instructions_en'=>sanitize_textarea_field($in['instructions_en']??'')];}$shipping=[];foreach(self::governorates() as $ar=>$en){$z=$_POST['shipping'][$ar]??[];$shipping[$ar]=['enabled'=>!empty($z['enabled'])?1:0,'fee'=>max(0,(float)($z['fee']??0)),'free_threshold'=>max(0,(float)($z['free_threshold']??0)),'days'=>max(1,min(30,(int)($z['days']??3)))];}update_option('tager_v24_settings',['methods'=>$methods,'bank_details'=>sanitize_textarea_field($_POST['bank_details']??''),'instapay_address'=>sanitize_text_field($_POST['instapay_address']??''),'wallet_number'=>sanitize_text_field($_POST['wallet_number']??''),'card_demo'=>!empty($_POST['card_demo'])?1:0,'shipping_enabled'=>!empty($_POST['shipping_enabled'])?1:0,'shipping_mode'=>in_array(($_POST['shipping_mode']??'governorate'),['governorate','flat'],true)?$_POST['shipping_mode']:'governorate','flat_shipping_fee'=>max(0,(float)($_POST['flat_shipping_fee']??0)),'free_shipping_enabled'=>!empty($_POST['free_shipping_enabled'])?1:0,'free_shipping_threshold'=>max(0,(float)($_POST['free_shipping_threshold']??0)),'charge_per_vendor'=>!empty($_POST['charge_per_vendor'])?1:0,'per_vendor_handling_fee'=>max(0,(float)($_POST['per_vendor_handling_fee']??0)),'mixed_cart_shipping_surcharge_type'=>in_array(($_POST['mixed_cart_shipping_surcharge_type']??'fixed'),['fixed','percent'],true)?$_POST['mixed_cart_shipping_surcharge_type']:'fixed','mixed_cart_shipping_surcharge'=>max(0,(float)($_POST['mixed_cart_shipping_surcharge']??0)),'mixed_cart_fee_percent'=>max(0,min(20,(float)($_POST['mixed_cart_fee_percent']??1.5))),'platform_fee_type'=>in_array(($_POST['platform_fee_type']??'fixed'),['fixed','percent'],true)?$_POST['platform_fee_type']:'fixed','platform_fee'=>max(0,(float)($_POST['platform_fee']??0)),'small_order_threshold'=>max(0,(float)($_POST['small_order_threshold']??0)),'small_order_fee'=>max(0,(float)($_POST['small_order_fee']??0)),'cod_max_total'=>max(0,(float)($_POST['cod_max_total']??0)),'pickup_enabled'=>!empty($_POST['pickup_enabled'])?1:0,'pickup_address'=>sanitize_text_field($_POST['pickup_address']??''),'express_enabled'=>!empty($_POST['express_enabled'])?1:0,'express_fee'=>max(0,(float)($_POST['express_fee']??0)),'express_days'=>max(1,min(10,(int)($_POST['express_days']??1))),'shipping'=>$shipping]);wp_safe_redirect(admin_url('admin.php?page=tager-v24-payments&updated=1'));exit;}
